-- Acts 10: Cornelius and the Opening of the Gospel to the Gentiles

-- 1. Chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 10,
  'Acts 10 is the theological watershed of the early church. Cornelius, a Roman centurion of the Italian cohort stationed in Caesarea Maritima — devout, generous, and God-fearing but uncircumcised — receives an angelic vision directing him to send for a certain Peter at Joppa. The next day, as the centurion''s messengers approach, Peter on the rooftop is given his own trance-vision: a great sheet descending with every kind of clean and unclean creature, and a divine voice three times commanding, "Rise, Peter; kill, and eat." When the Spirit directs him to accompany the men "nothing doubting," Peter makes the historic journey north to a Gentile home. There he confesses what God had taught him in the vision — that he must not call any person common or unclean — and hears Cornelius recount his own angelic visitation. Peter''s sermon sets forth the programmatic declaration of Acts: "God is no respecter of persons." He preaches Jesus of Nazareth, anointed by the Spirit, crucified and raised, now Judge of living and dead, and offering remission of sins through his name to "whosoever believeth." As he speaks, the Holy Spirit falls on the uncircumcised hearers in unmistakable Pentecostal fashion — they speak with tongues and magnify God — and the Jewish believers accompanying Peter are astonished. Unable to resist what God himself had authorized, Peter commands their baptism in water. The Jerusalem assumption that the gospel was for Israel first and only becomes a Jerusalem defense in chapter 11. Acts 10 is nothing less than the inclusion of the Gentiles by divine decree — the charter text of the multi-ethnic church.',
  'God is No Respecter of Persons: the Gentile Pentecost',
  'ἀπροσωπολήμπτης',
  'no respecter of persons, impartial',
  '["Cornelius''s vision at Caesarea (vv.1-8)", "Peter''s rooftop vision of the sheet (vv.9-16)", "The messengers arrive; Peter is directed by the Spirit (vv.17-23)", "Peter enters Cornelius''s house (vv.24-33)", "Peter''s Gentile-inclusive sermon (vv.34-43)", "The Spirit falls on the Gentiles; baptism follows (vv.44-48)"]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- 2. Verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'There was a certain man in Caesarea called Cornelius, a centurion of the band called the Italian band,',
   'Ἀνὴρ δέ τις ἐν Καισαρείᾳ ὀνόματι Κορνήλιος, ἑκατοντάρχης ἐκ σπείρης τῆς καλουμένης Ἰταλικῆς,',
   'Anēr de tis en Kaisareia onomati Kornēlios, hekatontarchēs ek speirēs tēs kaloumenēs Italikēs,',
   'Caesarea Maritima was the Roman provincial capital of Judea, a planned port-city built by Herod the Great. Cornelius bears a famous Roman gens name (Sulla freed 10,000 men called Cornelii in 82 BC). "Hekatontarchēs" ("centurion") commanded a century (nominally 100 men); the "Italian cohort" (Cohors II Italica Civium Romanorum Voluntariorum) is attested in inscriptions from mid-first century Syria-Judea.',
   'God''s sovereign choice often falls on those outside the covenant community. The first decisive Gentile convert is neither a Jewish proselyte nor a philosophical seeker but a Roman military officer — the very embodiment of the pagan empire.'),
  (2, 'A devout man, and one that feared God with all his house, which gave much alms to the people, and prayed to God alway.',
   'εὐσεβὴς καὶ φοβούμενος τὸν θεὸν σὺν παντὶ τῷ οἴκῳ αὐτοῦ, ποιῶν ἐλεημοσύνας πολλὰς τῷ λαῷ καὶ δεόμενος τοῦ θεοῦ διὰ παντός,',
   'Eusebēs kai phoboumenos ton theon syn panti tō oikō autou, poiōn eleēmosynas pollas tō laō kai deomenos tou theou dia pantos,',
   '"Phoboumenos ton theon" ("fearing God") is a technical term for Gentiles who worshipped Israel''s God and attended synagogue without being circumcised proselytes. Cornelius''s three marks — prayer, almsgiving, fear of God — are the traditional pillars of Jewish piety (cf. Tobit 12:8; Matt 6:1-18). Yet despite all this, he needs the gospel.',
   'Moral sincerity and religious devotion do not save apart from explicit faith in Christ. Cornelius''s exemplary life prepares him for conversion but does not replace it; salvation comes only through Jesus, even for those who already fear God.'),
  (3, 'He saw in a vision evidently about the ninth hour of the day an angel of God coming in to him, and saying unto him, Cornelius.',
   'εἶδεν ἐν ὁράματι φανερῶς ὡσεὶ περὶ ὥραν ἐνάτην τῆς ἡμέρας ἄγγελον τοῦ θεοῦ εἰσελθόντα πρὸς αὐτὸν καὶ εἰπόντα αὐτῷ· Κορνήλιε.',
   'Eiden en horamati phanerōs hōsei peri hōran enatēn tēs hēmeras angelon tou theou eiselthonta pros auton kai eiponta autō; Kornēlie.',
   'The ninth hour (3 pm) was the Jewish hour of afternoon prayer (3:1); Cornelius was at prayer, keeping synagogue hours. "Phanerōs" ("clearly, manifestly") emphasizes the objective, waking nature of the revelation — not a dream. The personal name on the angel''s lips echoes Ananias''s summons (9:10).',
   'God meets the praying heart with specific, personal revelation. The disciplines of prayer and almsgiving are not meritorious but receptive; they position the soul to receive the clearer word God is waiting to speak.'),
  (4, 'And when he looked on him, he was afraid, and said, What is it, Lord? And he said unto him, Thy prayers and thine alms are come up for a memorial before God.',
   'ὁ δὲ ἀτενίσας αὐτῷ καὶ ἔμφοβος γενόμενος εἶπεν· τί ἐστιν, κύριε; εἶπεν δὲ αὐτῷ· αἱ προσευχαί σου καὶ αἱ ἐλεημοσύναι σου ἀνέβησαν εἰς μνημόσυνον ἔμπροσθεν τοῦ θεοῦ.',
   'Ho de atenisas autō kai emphobos genomenos eipen; ti estin, kyrie? Eipen de autō; hai proseuchai sou kai hai eleēmosynai sou anebēsan eis mnēmosynon emprosthen tou theou.',
   '"Mnēmosynon" ("memorial") is Septuagint cultic language for a portion of the grain offering burned as a "reminder" to God (Lev 2:2; 24:7). Cornelius''s prayers and alms ascend as incense — a lay, Gentile offering that God honors. No saving merit is implied; God remembers and now answers.',
   'God marks the worship of the humble with sovereign attention. The smoke of Cornelius''s sincerity rises to heaven as a true memorial, to be answered with the saving knowledge of Christ — grace not earned but granted in response to grace already given.'),
  (5, 'And now send men to Joppa, and call for one Simon, whose surname is Peter:',
   'καὶ νῦν πέμψον ἄνδρας εἰς Ἰόππην καὶ μετάπεμψαι Σίμωνά τινα ὃς ἐπικαλεῖται Πέτρος·',
   'Kai nyn pempson andras eis Ioppēn kai metapempsai Simōna tina hos epikaleitai Petros;',
   'God directs the God-fearing Gentile not to the angel for instruction but to a human preacher. The divine method is always mediated proclamation — the message must come through a messenger. This safeguards the incarnational principle of gospel transmission.',
   'God ordains preachers, not angels, to carry the gospel. Even direct divine revelation directs the hearer to an appointed human witness, preserving the church''s mediating role in the saving of souls.'),
  (6, 'He lodgeth with one Simon a tanner, whose house is by the sea side: he shall tell thee what thou oughtest to do.',
   'οὗτος ξενίζεται παρά τινι Σίμωνι βυρσεῖ, ᾧ ἐστιν οἰκία παρὰ θάλασσαν.',
   'Houtos xenizetai para tini Simōni byrsei, hō estin oikia para thalassan.',
   'The specific address is given; divine providence coordinates the smallest details. The tanner''s house would be on the sea edge because the work required abundant water and produced offensive odors considered ritually impure. Peter''s lodging there already signals his softening boundaries.',
   'The details of divine guidance are as trustworthy as its grand strokes. God who orders Pentecost also orders addresses; the Christian walks confidently in particulars, not merely in generalities.'),
  (7, 'And when the angel which spake unto Cornelius was departed, he called two of his household servants, and a devout soldier of them that waited on him continually;',
   'ὡς δὲ ἀπῆλθεν ὁ ἄγγελος ὁ λαλῶν αὐτῷ, φωνήσας δύο τῶν οἰκετῶν καὶ στρατιώτην εὐσεβῆ τῶν προσκαρτερούντων αὐτῷ,',
   'Hōs de apēlthen ho angelos ho lalōn autō, phōnēsas dyo tōn oiketōn kai stratiōtēn eusebē tōn proskarterountōn autō,',
   'Cornelius''s influence has already shaped his household — his domestic servants are at hand, and one of his adjutant soldiers is "devout" (eusebēs) like his commander. Roman military households often mirrored the religious orientation of the head.',
   'Faithful household leadership produces contagious piety. The commander''s fear of God spreads through his servants and soldiers; Christian influence first forms those nearest before it reaches those farthest.'),
  (8, 'And when he had declared all these things unto them, he sent them to Joppa.',
   'καὶ ἐξηγησάμενος ἅπαντα αὐτοῖς ἀπέστειλεν αὐτοὺς εἰς τὴν Ἰόππην.',
   'Kai exēgēsamenos hapanta autois apesteilen autous eis tēn Ioppēn.',
   'Caesarea to Joppa is about 32 miles south along the coast — roughly a day''s vigorous march. Cornelius dispatches promptly; obedience to revelation is immediate.',
   'Prompt obedience to partial revelation secures further light. God reveals more to those who move on what he has already shown.'),
  (9, 'On the morrow, as they went on their journey, and drew nigh unto the city, Peter went up upon the housetop to pray about the sixth hour:',
   'Τῇ δὲ ἐπαύριον ὁδοιπορούντων ἐκείνων καὶ τῇ πόλει ἐγγιζόντων ἀνέβη Πέτρος ἐπὶ τὸ δῶμα προσεύξασθαι περὶ ὥραν ἕκτην.',
   'Tē de epaurion hodoiporountōn ekeinōn kai tē polei engizontōn anebē Petros epi to dōma proseuxasthai peri hōran hektēn.',
   'The sixth hour (noon) was not a fixed prayer hour but Peter''s discretionary devotion. "Dōma" ("housetop") is the flat Middle Eastern roof, a customary place of prayer, cool air, and privacy. Divine providence coordinates the movements of messengers and the timing of visions within the same hour.',
   'God synchronizes his providence across distances. While God-fearing Gentiles travel toward Peter, the Spirit prepares Peter to receive them; such coordination is the silent rhythm of every mission God initiates.'),
  (10, 'And he became very hungry, and would have eaten: but while they made ready, he fell into a trance,',
   'ἐγένετο δὲ πρόσπεινος καὶ ἤθελεν γεύσασθαι· παρασκευαζόντων δὲ αὐτῶν ἐγένετο ἐπ’ αὐτὸν ἔκστασις,',
   'Egeneto de prospeinos kai ēthelen geusasthai; paraskeuazontōn de autōn egeneto ep'' auton ekstasis,',
   '"Ekstasis" ("trance, ecstasy") literally "standing outside oneself" — the OT language of prophetic rapture. Hunger is divinely deployed as the sensory bridge into the vision. Peter''s bodily condition becomes the occasion of theological revolution.',
   'God employs ordinary bodily rhythms as vehicles of revelation. Fasting, hunger, rest, and watchfulness are not incidental; the Spirit works through physical conditions to speak decisively to the soul.'),
  (11, 'And saw heaven opened, and a certain vessel descending unto him, as it had been a great sheet knit at the four corners, and let down to the earth:',
   'καὶ θεωρεῖ τὸν οὐρανὸν ἀνεῳγμένον καὶ καταβαῖνον σκεῦός τι ὡς ὀθόνην μεγάλην τέσσαρσιν ἀρχαῖς καθιέμενον ἐπὶ τῆς γῆς,',
   'Kai theōrei ton ouranon aneōgmenon kai katabainon skeuos ti hōs othonēn megalēn tessarsin archais kathiemenon epi tēs gēs,',
   '"Ouranon aneōgmenon" ("heaven opened") echoes Jesus'' baptism (Matt 3:16) and Stephen''s vision (7:56) — the apocalyptic opening of the divine throne-room. The "four corners" represent the four winds/quarters of the world (Isa 11:12), so the sheet functions as a symbol of the whole creation under heaven.',
   'What God opens from heaven reshapes earth. The "sheet" is a visual parable of a redeemed creation in which nothing God has made is inherently unclean; the gospel''s cosmic reach is spatially dramatized.'),
  (12, 'Wherein were all manner of fourfooted beasts of the earth, and wild beasts, and creeping things, and fowls of the air.',
   'ἐν ᾧ ὑπῆρχεν πάντα τὰ τετράποδα καὶ ἑρπετὰ τῆς γῆς καὶ πετεινὰ τοῦ οὐρανοῦ.',
   'En hō hypērchen panta ta tetrapoda kai herpeta tēs gēs kai peteina tou ouranou.',
   'The triad "tetrapoda kai herpeta kai peteina" deliberately echoes the creation categories of Genesis 1:24-26 and Leviticus 11 — all classes of land animals, reptiles, and birds, both clean and unclean. The vision encompasses the full Levitical menagerie.',
   'The old food laws served a symbolic, pedagogical purpose, fencing Israel from the nations until the Messiah. In Christ that fence is now removed; no nation may any longer be treated as ceremonially untouchable.'),
  (13, 'And there came a voice to him, Rise, Peter; kill, and eat.',
   'καὶ ἐγένετο φωνὴ πρὸς αὐτόν· ἀναστάς, Πέτρε, θῦσον καὶ φάγε.',
   'Kai egeneto phōnē pros auton; anastas, Petre, thyson kai phage.',
   '"Thyson" ("kill, slaughter, sacrifice") is sacrificial language in the LXX. The command is liturgical: slay and consume what the Torah forbids. The voice does not argue from hunger or expediency but commands on its own authority.',
   'The authority of the risen Christ now supersedes Levitical restriction. The voice that called forth the old covenant now freely abrogates its dietary sign, transferring holiness from the table of Moses to the table of the Lord.'),
  (14, 'But Peter said, Not so, Lord; for I have never eaten any thing that is common or unclean.',
   'ὁ δὲ Πέτρος εἶπεν· μηδαμῶς, κύριε, ὅτι οὐδέποτε ἔφαγον πᾶν κοινὸν καὶ ἀκάθαρτον.',
   'Ho de Petros eipen; mēdamōs, kyrie, hoti oudepote ephagon pan koinon kai akatharton.',
   '"Mēdamōs, kyrie" ("By no means, Lord") is a striking grammatical paradox — if the speaker is "Lord," refusal is impossible. "Koinos" ("common") is the later Jewish term for ritually defiling; "akathartos" ("unclean") is Levitical. Peter''s scruples are proudly reported as lifelong; faithful piety needs its frame redrawn.',
   'Sincere religious conscience, if unmeasured by fresh obedience to Christ, can become a barrier to God''s expanding work. The Lord never contradicts himself, but his revelation advances; what was once forbidden may now be commanded.'),
  (15, 'And the voice spake unto him again the second time, What God hath cleansed, that call not thou common.',
   'καὶ φωνὴ πάλιν ἐκ δευτέρου πρὸς αὐτόν· ἃ ὁ θεὸς ἐκαθάρισεν, σὺ μὴ κοίνου.',
   'Kai phōnē palin ek deuterou pros auton; ha ho theos ekatharisen, sy mē koinou.',
   '"Ha ho theos ekatharisen" ("what God has cleansed") is aorist — a definitive, decisive divine act. The imperative "mē koinou" ("do not make common") forbids Peter to undo what God has done. The principle will reapply beyond food to persons (v.28).',
   'Divine cleansing is absolute and non-negotiable. Whatever God has declared clean, the believer has no authority to treat as polluted; this principle grounds the full ethnic inclusion of Gentile believers.'),
  (16, 'This was done thrice: and the vessel was received up again into heaven.',
   'τοῦτο δὲ ἐγένετο ἐπὶ τρίς, καὶ εὐθὺς ἀνελήμφθη τὸ σκεῦος εἰς τὸν οὐρανόν.',
   'Touto de egeneto epi tris, kai euthys anelēmphthē to skeuos eis ton ouranon.',
   'Threefold repetition is the pattern of divine confirmation (cf. Peter''s threefold denial and restoration, John 21). "Anelēmphthē" ("was taken up") uses the same verb as the ascension of Christ (1:2, 11), underscoring the heavenly origin and authority of the vision.',
   'God confirms decisive revelations with repetition. What is declared thrice from heaven is irrevocable and intended to overcome deep resistance; certainty is given commensurate with the magnitude of change required.'),
  (17, 'Now while Peter doubted in himself what this vision which he had seen should mean, behold, the men which were sent from Cornelius had made enquiry for Simon''s house, and stood before the gate,',
   'Ὡς δὲ ἐν ἑαυτῷ διηπόρει ὁ Πέτρος τί ἂν εἴη τὸ ὅραμα ὃ εἶδεν, ἰδοὺ οἱ ἄνδρες οἱ ἀπεσταλμένοι ὑπὸ τοῦ Κορνηλίου διερωτήσαντες τὴν οἰκίαν τοῦ Σίμωνος ἐπέστησαν ἐπὶ τὸν πυλῶνα,',
   'Hōs de en heautō diēporei ho Petros ti an eiē to horama ho eiden, idou hoi andres hoi apestalmenoi hypo tou Kornēliou dierōtēsantes tēn oikian tou Simōnos epestēsan epi ton pylōna,',
   '"Diēporei" ("was perplexed") — the vision''s meaning is not self-evident; God''s providence delivers the interpretation by means of flesh-and-blood visitors. The moment of puzzlement is interrupted by the very people whose arrival will explain the vision.',
   'Divine revelation is often interpreted by divine providence. What the Spirit shows in trance, the Spirit confirms at the gate; the two coordinates — vision and circumstance — form the grammar of guidance.'),
  (18, 'And called, and asked whether Simon, which was surnamed Peter, were lodged there.',
   'καὶ φωνήσαντες ἐπυνθάνοντο εἰ Σίμων ὁ ἐπικαλούμενος Πέτρος ἐνθάδε ξενίζεται.',
   'Kai phōnēsantes epynthanonto ei Simōn ho epikaloumenos Petros enthade xenizetai.',
   'The precise name given by the angel (v.5) is used by the messengers — a corroboration of divine coordination across independent revelations.',
   'God authenticates his guidance by exact correspondence between revelations given to different parties. The name on the angel''s lips becomes the name on the messenger''s lips — divine choreography confirmed.'),
  (19, 'While Peter thought on the vision, the Spirit said unto him, Behold, three men seek thee.',
   'τοῦ δὲ Πέτρου διενθυμουμένου περὶ τοῦ ὁράματος εἶπεν τὸ πνεῦμα· ἰδοὺ ἄνδρες τρεῖς ζητοῦσίν σε·',
   'Tou de Petrou dienthymoumenou peri tou horamatos eipen to pneuma; idou andres treis zētousin se;',
   'The Spirit speaks directly to Peter — the only explicit Spirit-speech in this form in Acts. Peter is still pondering when the personal direction comes. The Spirit knows the visitors'' number before Peter has seen them.',
   'The Holy Spirit is a personal guide who speaks with specificity. He knows who is at the gate before the door is opened; his guidance is not vague impression but sometimes precise, informative, and confirmatory.'),
  (20, 'Arise therefore, and get thee down, and go with them, doubting nothing: for I have sent them.',
   'ἀλλὰ ἀναστὰς κατάβηθι καὶ πορεύου σὺν αὐτοῖς μηδὲν διακρινόμενος, ὅτι ἐγὼ ἀπέσταλκα αὐτούς.',
   'Alla anastas katabēthi kai poreuou syn autois mēden diakrinomenos, hoti egō apestalka autous.',
   '"Mēden diakrinomenos" ("doubting nothing, making no distinction") plays on both meanings: do not hesitate, and do not discriminate. "Egō apestalka" ("I have sent") puts the Spirit in the position of the Sender: pagans at the gate have been dispatched by God himself.',
   'The Spirit is a Sender of Gentile inquirers to apostolic homes. Every open door to the gospel is authored in heaven; the missionary''s task is to recognize and follow the Spirit''s prior movement.'),
  (21, 'Then Peter went down to the men which were sent unto him from Cornelius; and said, Behold, I am he whom ye seek: what is the cause wherefore ye are come?',
   'καταβὰς δὲ Πέτρος πρὸς τοὺς ἄνδρας εἶπεν· ἰδοὺ ἐγώ εἰμι ὃν ζητεῖτε· τίς ἡ αἰτία δι’ ἣν πάρεστε;',
   'Katabas de Petros pros tous andras eipen; idou egō eimi hon zēteite; tis hē aitia di'' hēn pareste?',
   'Peter''s first words frame a commendable posture: immediate self-disclosure and inquiry. He asks the reason; good ministry begins with understanding the visitor''s need.',
   'Ministry begins with listening. Even Spirit-directed missionaries ask, rather than assume, what the Spirit has already done in the hearer''s life.'),
  (22, 'And they said, Cornelius the centurion, a just man, and one that feareth God, and of good report among all the nation of the Jews, was warned from God by an holy angel to send for thee into his house, and to hear words of thee.',
   'οἱ δὲ εἶπαν· Κορνήλιος ἑκατοντάρχης, ἀνὴρ δίκαιος καὶ φοβούμενος τὸν θεὸν, μαρτυρούμενός τε ὑπὸ ὅλου τοῦ ἔθνους τῶν Ἰουδαίων, ἐχρηματίσθη ὑπὸ ἀγγέλου ἁγίου μεταπέμψασθαί σε εἰς τὸν οἶκον αὐτοῦ καὶ ἀκοῦσαι ῥήματα παρὰ σοῦ.',
   'Hoi de eipan; Kornēlios hekatontarchēs, anēr dikaios kai phoboumenos ton theon, martyroumenos te hypo holou tou ethnous tōn Ioudaiōn, echrēmatisthē hypo angelou hagiou metapempsasthai se eis ton oikon autou kai akousai rhēmata para sou.',
   '"Martyroumenos" ("well reported of") — Cornelius''s testimony among all the nation of the Jews preempts Peter''s scruples. The goal is explicitly "words" (rhēmata) — he must hear the specific apostolic message, which is more than Jewish piety or angelic message can give.',
   'Even the most devout Gentile needs the specific word of the gospel. Piety opens the door; proclamation delivers Christ. The angel sent for the preacher, not the preacher for the angel.'),
  (23, 'Then called he them in, and lodged them. And on the morrow Peter went away with them, and certain brethren from Joppa accompanied him.',
   'εἰσκαλεσάμενος οὖν αὐτοὺς ἐξένισεν. τῇ δὲ ἐπαύριον ἀναστὰς ἐξῆλθεν σὺν αὐτοῖς, καί τινες τῶν ἀδελφῶν τῶν ἀπὸ Ἰόππης συνῆλθον αὐτῷ.',
   'Eiskalesamenos oun autous exenisen. Tē de epaurion anastas exēlthen syn autois, kai tines tōn adelphōn tōn apo Ioppēs synēlthon autō.',
   'Peter''s first act of Gentile hospitality is to lodge the messengers — a small crossing of boundary that rehearses the larger one. Six brethren (11:12) accompany him; they will become corroborating witnesses at the Jerusalem council.',
   'God surrounds his servants with corroborating witnesses for decisive acts. The company of six brothers from Joppa provides unshakable testimony for what Peter will shortly defend before the Jerusalem church.'),
  (24, 'And the morrow after they entered into Caesarea. And Cornelius waited for them, and had called together his kinsmen and near friends.',
   'τῇ δὲ ἐπαύριον εἰσῆλθον εἰς τὴν Καισάρειαν. ὁ δὲ Κορνήλιος ἦν προσδοκῶν αὐτοὺς συγκαλεσάμενος τοὺς συγγενεῖς αὐτοῦ καὶ τοὺς ἀναγκαίους φίλους.',
   'Tē de epaurion eisēlthon eis tēn Kaisareian. Ho de Kornēlios ēn prosdokōn autous synkalesamenos tous syngeneis autou kai tous anankaious philous.',
   'Cornelius has assembled an evangelistic gathering in advance — "kinsmen and near friends" — expecting the gospel before it arrives. "Prosdokōn" ("waiting expectantly") is the posture of faith; he trusts the vision enough to prepare an audience.',
   'Genuine openness to divine revelation prompts preemptive gathering. The centurion prepares a Gentile congregation before the apostle has preached a sermon; expectation shapes the first Gentile Pentecost.'),
  (25, 'And as Peter was coming in, Cornelius met him, and fell down at his feet, and worshipped him.',
   'Ὡς δὲ ἐγένετο τοῦ εἰσελθεῖν τὸν Πέτρον, συναντήσας αὐτῷ ὁ Κορνήλιος πεσὼν ἐπὶ τοὺς πόδας προσεκύνησεν.',
   'Hōs de egeneto tou eiselthein ton Petron, synantēsas autō ho Kornēlios pesōn epi tous podas prosekynēsen.',
   '"Prosekynēsen" may here mean either prostrate homage to a superior or outright worship — Cornelius, a Roman used to emperor worship, extends the highest honor he knows. Peter''s refusal clarifies which it was.',
   'Every human being — however godly, apostolic, or angelic — is a fellow-servant, not an object of worship. Christian orthodoxy is jealous of the unique glory due to God alone.'),
  (26, 'But Peter took him up, saying, Stand up; I myself also am a man.',
   'ὁ δὲ Πέτρος ἤγειρεν αὐτὸν λέγων· ἀνάστηθι· καὶ ἐγὼ αὐτὸς ἄνθρωπός εἰμι.',
   'Ho de Petros ēgeiren auton legōn; anastēthi; kai egō autos anthrōpos eimi.',
   'Peter''s refusal contrasts pointedly with the demon-possessed girl''s witness at 16:17 and the Lystran crowd at 14:14-15 and (most emphatically) the angel of Rev 22:9. Christian apostles are definitively mortal men.',
   'True ministers of the gospel decisively refuse divine honor. The minister is a voice pointing to the Word; veneration of the messenger poisons the message.'),
  (27, 'And as he talked with him, he went in, and found many that were come together.',
   'καὶ συνομιλῶν αὐτῷ εἰσῆλθεν, καὶ εὑρίσκει συνεληλυθότας πολλούς,',
   'Kai synomilōn autō eisēlthen, kai heuriskei synelēlythotas pollous,',
   '"Synomilōn" ("conversing") — ordinary human talk continues as Peter crosses the threshold. The conversational texture underscores the revolutionary normalcy: a Jewish apostle simply walks into a Gentile house.',
   'Grace transforms under the cover of ordinary conversation. The most decisive crossings of Christian history often happen in quiet dialogue and unremarkable entries.'),
  (28, 'And he said unto them, Ye know how that it is an unlawful thing for a man that is a Jew to keep company, or come unto one of another nation; but God hath shewed me that I should not call any man common or unclean.',
   'ἔφη τε πρὸς αὐτούς· ὑμεῖς ἐπίστασθε ὡς ἀθέμιτόν ἐστιν ἀνδρὶ Ἰουδαίῳ κολλᾶσθαι ἢ προσέρχεσθαι ἀλλοφύλῳ· κἀμοὶ ὁ θεὸς ἔδειξεν μηδένα κοινὸν ἢ ἀκάθαρτον λέγειν ἄνθρωπον.',
   'Ephē te pros autous; hymeis epistasthe hōs athemiton estin andri Ioudaiō kollasthai ē proserchesthai allophylō; kamoi ho theos edeixen mēdena koinon ē akatharton legein anthrōpon.',
   '"Athemiton" ("unlawful") refers not to Torah itself but to the rabbinic halakhic extension that separated strictly from Gentiles. Peter here applies the sheet-vision beyond food: "no man" is to be called common. The theological inference is explicit.',
   'God''s cleansing in Christ reconfigures categories of persons, not just categories of food. The great social leveling of the new covenant issues directly from the sovereign declaration: what God has cleansed is clean.'),
  (29, 'Therefore came I unto you without gainsaying, as soon as I was sent for: I ask therefore for what intent ye have sent for me?',
   'διὸ καὶ ἀναντιρρήτως ἦλθον μεταπεμφθείς. πυνθάνομαι οὖν τίνι λόγῳ μετεπέμψασθέ με.',
   'Dio kai anantirrētōs ēlthon metapemphtheis. Pynthanomai oun tini logō metepempsasthe me.',
   '"Anantirrētōs" ("without contradiction, without raising objection") — a compact description of submitted obedience. Peter invites Cornelius to tell his story, further establishing the divine orchestration that both sides may witness.',
   'Spirit-led ministry submits without objection to the Spirit''s mission. The "why" of each gospel call is often revealed only after the obedience has been rendered.'),
  (30, 'And Cornelius said, Four days ago I was fasting until this hour; and at the ninth hour I prayed in my house, and, behold, a man stood before me in bright clothing,',
   'καὶ ὁ Κορνήλιος ἔφη· ἀπὸ τετάρτης ἡμέρας μέχρι ταύτης τῆς ὥρας ἤμην τὴν ἐνάτην προσευχόμενος ἐν τῷ οἴκῳ μου, καὶ ἰδοὺ ἀνὴρ ἔστη ἐνώπιόν μου ἐν ἐσθῆτι λαμπρᾷ',
   'Kai ho Kornēlios ephē; apo tetartēs hēmeras mechri tautēs tēs hōras ēmēn tēn enatēn proseuchomenos en tō oikō mou, kai idou anēr estē enōpion mou en esthēti lamprā',
   'The four-day timeline is precise: day 1 — vision; day 2 — messengers travel; day 3 — Peter travels; day 4 — arrival. "Bright clothing" (esthēti lamprā) signals heavenly origin (cf. Luke 24:4).',
   'God honors fasting and prayer with fresh revelation. Humble disciplines produce spiritual vision not by merit but by preparing the heart to recognize heavenly presence when it arrives.'),
  (31, 'And said, Cornelius, thy prayer is heard, and thine alms are had in remembrance in the sight of God.',
   'καὶ φησίν· Κορνήλιε, εἰσηκούσθη σου ἡ προσευχὴ καὶ αἱ ἐλεημοσύναι σου ἐμνήσθησαν ἐνώπιον τοῦ θεοῦ.',
   'Kai phēsin; Kornēlie, eisēkousthē sou hē proseuchē kai hai eleēmosynai sou emnēsthēsan enōpion tou theou.',
   '"Eisēkousthē" ("was heard") and "emnēsthēsan" ("were remembered") are divine passives. Cornelius''s history of prayer and giving is recorded in heaven''s ledger; now answered, not earned.',
   'God keeps faithful record of his people''s prayers and alms, even before formal conversion. No godly act is lost; the remembrance of heaven gathers every seeking deed toward the day of encounter with Christ.'),
  (32, 'Send therefore to Joppa, and call hither Simon, whose surname is Peter; he is lodged in the house of one Simon a tanner by the sea side: who, when he cometh, shall speak unto thee.',
   'πέμψον οὖν εἰς Ἰόππην καὶ μετακάλεσαι Σίμωνα ὃς ἐπικαλεῖται Πέτρος· οὗτος ξενίζεται ἐν οἰκίᾳ Σίμωνος βυρσέως παρὰ θάλασσαν.',
   'Pempson oun eis Ioppēn kai metakalesai Simōna hos epikaleitai Petros; houtos xenizetai en oikia Simōnos byrseōs para thalassan.',
   'Cornelius''s recall of the angelic instructions is precise, demonstrating his careful obedience. The repetition of the address for the public hearing creates a paired testimony confirming the divine appointment before everyone present.',
   'Testimony recited publicly strengthens corporate faith. What God did privately is meant to be shared openly; Christian witness often multiplies by its telling.'),
  (33, 'Immediately therefore I sent to thee; and thou hast well done that thou art come. Now therefore are we all here present before God, to hear all things that are commanded thee of God.',
   'ἐξαυτῆς οὖν ἔπεμψα πρὸς σέ, σύ τε καλῶς ἐποίησας παραγενόμενος. νῦν οὖν πάντες ἡμεῖς ἐνώπιον τοῦ θεοῦ πάρεσμεν ἀκοῦσαι πάντα τὰ προστεταγμένα σοι ὑπὸ τοῦ κυρίου.',
   'Exautēs oun epempsa pros se, sy te kalōs epoiēsas paragenomenos. Nyn oun pantes hēmeis enōpion tou theou paresmen akousai panta ta prostetagmena soi hypo tou kyriou.',
   '"Enōpion tou theou" ("in the presence of God") — the gathering is explicitly coram Deo. The Gentiles describe themselves as standing before God to receive his word; this is an extraordinary self-description for a hearer before the first gospel sermon they will ever hear.',
   'The ideal Christian hearing is conscious of God''s presence. When the ears are opened in the fear of the Lord, the word that comes is received as from God himself — exactly the response that produces Pentecostal fruit.'),
  (34, 'Then Peter opened his mouth, and said, Of a truth I perceive that God is no respecter of persons:',
   'ἀνοίξας δὲ Πέτρος τὸ στόμα εἶπεν· ἐπ’ ἀληθείας καταλαμβάνομαι ὅτι οὐκ ἔστιν προσωπολήμπτης ὁ θεός,',
   'Anoixas de Petros to stoma eipen; ep'' alētheias katalambanomai hoti ouk estin prosōpolēmptēs ho theos,',
   '"Prosōpolēmptēs" (literally "face-receiver") is a Septuagint idiom for partial judgment — God does not judge by outward appearance (cf. 1 Sam 16:7; Deut 10:17). The negation announces the programmatic doctrine of Acts: the gospel is for every nation without ethnic partiality.',
   'The impartiality of God grounds the worldwide mission. Because God does not show favoritism, neither may his church; ethnic, social, and national prejudice is excluded from the gospel by the very nature of the God who gives it.'),
  (35, 'But in every nation he that feareth him, and worketh righteousness, is accepted with him.',
   'ἀλλ’ ἐν παντὶ ἔθνει ὁ φοβούμενος αὐτὸν καὶ ἐργαζόμενος δικαιοσύνην δεκτὸς αὐτῷ ἐστιν.',
   'All'' en panti ethnei ho phoboumenos auton kai ergazomenos dikaiosynēn dektos autō estin.',
   '"Dektos" ("acceptable, welcome") does not mean already saved apart from Christ; it means that God accepts for further gospel-hearing all who genuinely seek him. Cornelius is the living example: accepted for hearing, not yet saved — but about to be.',
   'God''s welcoming providence precedes his saving grace. He draws God-fearers from every nation toward the gospel proclamation that alone can save them; acceptance for hearing is not confused with justification.'),
  (36, 'The word which God sent unto the children of Israel, preaching peace by Jesus Christ: (he is Lord of all:)',
   'τὸν λόγον ὃν ἀπέστειλεν τοῖς υἱοῖς Ἰσραὴλ εὐαγγελιζόμενος εἰρήνην διὰ Ἰησοῦ Χριστοῦ· οὗτός ἐστιν πάντων κύριος,',
   'Ton logon hon apesteilen tois huiois Israēl euangelizomenos eirēnēn dia Iēsou Christou; houtos estin pantōn kyrios,',
   '"Pantōn kyrios" ("Lord of all") — an emphatic parenthesis: the Christ proclaimed to Israel is the Lord of every people, including Romans. This single phrase anchors the universality of Christ''s dominion.',
   'Jesus Christ is the Lord of every nation, not merely the Messiah of the Jews. The ethnic particularity of Israel''s history served the universal kingship of its promised King; now the confession of Christ is offered to and required of all.'),
  (37, 'That word, I say, ye know, which was published throughout all Judaea, and began from Galilee, after the baptism which John preached;',
   'ὑμεῖς οἴδατε τὸ γενόμενον ῥῆμα καθ’ ὅλης τῆς Ἰουδαίας, ἀρξάμενος ἀπὸ τῆς Γαλιλαίας μετὰ τὸ βάπτισμα ὃ ἐκήρυξεν Ἰωάννης,',
   'Hymeis oidate to genomenon rhēma kath'' holēs tēs Ioudaias, arxamenos apo tēs Galilaias meta to baptisma ho ekēryxen Iōannēs,',
   'Peter appeals to public knowledge: "you know" the recent events concerning Jesus. The gospel is not esoteric revelation but verifiable public history. The sermon follows the rough outline of the Gospel of Mark, beginning with John the Baptist.',
   'Christian preaching is grounded in public facts. The apostolic gospel is not a private revelation but the announcement of historical events, and it always remains falsifiable in principle — and confirmed in fact.'),
  (38, 'How God anointed Jesus of Nazareth with the Holy Ghost and with power: who went about doing good, and healing all that were oppressed of the devil; for God was with him.',
   'Ἰησοῦν τὸν ἀπὸ Ναζαρέθ, ὡς ἔχρισεν αὐτὸν ὁ θεὸς πνεύματι ἁγίῳ καὶ δυνάμει, ὃς διῆλθεν εὐεργετῶν καὶ ἰώμενος πάντας τοὺς καταδυναστευομένους ὑπὸ τοῦ διαβόλου, ὅτι ὁ θεὸς ἦν μετ’ αὐτοῦ.',
   'Iēsoun ton apo Nazareth, hōs echrisen auton ho theos pneumati hagiō kai dynamei, hos diēlthen euergetōn kai iōmenos pantas tous katadynasteuomenous hypo tou diabolou, hoti ho theos ēn met'' autou.',
   '"Echrisen" ("anointed") puns on "Christos" — Jesus is the anointed one par excellence. The summary of his ministry — "went about doing good, and healing all that were oppressed of the devil" — is the most compressed biography of Christ''s public work in the NT.',
   'Christ''s earthly ministry was a concerted assault on satanic oppression, authorized by the Father''s anointing and empowered by the Holy Spirit. This trinitarian pattern of ministry is paradigmatic for the church that follows him.'),
  (39, 'And we are witnesses of all things which he did both in the land of the Jews, and in Jerusalem; whom they slew and hanged on a tree:',
   'καὶ ἡμεῖς μάρτυρες πάντων ὧν ἐποίησεν ἔν τε τῇ χώρᾳ τῶν Ἰουδαίων καὶ ἐν Ἰερουσαλήμ, ὃν καὶ ἀνεῖλαν κρεμάσαντες ἐπὶ ξύλου.',
   'Kai hēmeis martyres pantōn hōn epoiēsen en te tē chōra tōn Ioudaiōn kai en Ierousalēm, hon kai aneilan kremasantes epi xylou.',
   '"Epi xylou" ("on a tree") evokes Deuteronomy 21:23 — the one hanged is cursed of God. Peter freely admits the shame of the cross; the hideous death is not hidden but placed at the center of the proclamation.',
   'The crucifixion, which appeared as God''s curse, is proclaimed as God''s redemption. Christian preaching does not minimize but magnifies the cross, finding in its scandal the very heart of the gospel.'),
  (40, 'Him God raised up the third day, and shewed him openly;',
   'τοῦτον ὁ θεὸς ἤγειρεν τῇ τρίτῃ ἡμέρᾳ καὶ ἔδωκεν αὐτὸν ἐμφανῆ γενέσθαι,',
   'Touton ho theos ēgeiren tē tritē hēmera kai edōken auton emphanē genesthai,',
   '"Ēgeiren" ("raised") is God the Father''s act. "Emphanē" ("manifest, visible") — the Father granted the risen Christ to appear publicly (though not to all; see v.41).',
   'The resurrection is the Father''s vindication of the crucified Son and the foundation of every gospel offer. Without this historical, visible rising, Christianity has no message at all.'),
  (41, 'Not to all the people, but unto witnesses chosen before of God, even to us, who did eat and drink with him after he rose from the dead.',
   'οὐ παντὶ τῷ λαῷ, ἀλλὰ μάρτυσιν τοῖς προκεχειροτονημένοις ὑπὸ τοῦ θεοῦ, ἡμῖν, οἵτινες συνεφάγομεν καὶ συνεπίομεν αὐτῷ μετὰ τὸ ἀναστῆναι αὐτὸν ἐκ νεκρῶν·',
   'Ou panti tō laō, alla martysin tois prokecheirotonēmenois hypo tou theou, hēmin, hoitines synephagomen kai synepiomen autō meta to anastēnai auton ek nekrōn;',
   '"Synephagomen kai synepiomen" ("we ate and drank with him") — evidence of the bodily resurrection; a phantom cannot share food (Luke 24:42-43). The risen Christ is appointed to appear not to the curious world but to chosen witnesses whose testimony carries divine authority.',
   'The resurrection is historically verified by chosen witnesses whose table-fellowship with the risen Lord anchors the church''s apostolic confession. Christianity is not a myth but a testimony to events eaten and drunk with the Risen One.'),
  (42, 'And he commanded us to preach unto the people, and to testify that it is he which was ordained of God to be the Judge of quick and dead.',
   'καὶ παρήγγειλεν ἡμῖν κηρύξαι τῷ λαῷ καὶ διαμαρτύρασθαι ὅτι οὗτός ἐστιν ὁ ὡρισμένος ὑπὸ τοῦ θεοῦ κριτὴς ζώντων καὶ νεκρῶν.',
   'Kai parēngeilen hēmin kēryxai tō laō kai diamartyrasthai hoti houtos estin ho hōrismenos hypo tou theou kritēs zōntōn kai nekrōn.',
   '"Kritēs zōntōn kai nekrōn" ("judge of the living and the dead") — the comprehensive eschatological function of Christ. Peter does not offer a consumer gospel but announces a Judge whom every human being will meet.',
   'Preaching the gospel includes preaching coming judgment by Christ. The same Jesus who invites is the Judge who comes; the gospel that offers mercy also announces universal accountability at the hands of the crucified-risen Lord.'),
  (43, 'To him give all the prophets witness, that through his name whosoever believeth in him shall receive remission of sins.',
   'τούτῳ πάντες οἱ προφῆται μαρτυροῦσιν ἄφεσιν ἁμαρτιῶν λαβεῖν διὰ τοῦ ὀνόματος αὐτοῦ πάντα τὸν πιστεύοντα εἰς αὐτόν.',
   'Toutō pantes hoi prophētai martyrousin aphesin hamartiōn labein dia tou onomatos autou panta ton pisteuonta eis auton.',
   '"Panta ton pisteuonta" ("everyone who believes") — this universal offer is the hinge on which the Spirit falls. "Aphesin hamartiōn" ("remission of sins") through his name alone pinpoints the one way of salvation.',
   'Salvation is by faith alone, through the name of Christ alone, available to every believer without ethnic qualification. The prophetic Scriptures and the apostolic kerygma converge on this one proposition — and the Spirit thunders its "Amen."'),
  (44, 'While Peter yet spake these words, the Holy Ghost fell on all them which heard the word.',
   'Ἔτι λαλοῦντος τοῦ Πέτρου τὰ ῥήματα ταῦτα ἐπέπεσεν τὸ πνεῦμα τὸ ἅγιον ἐπὶ πάντας τοὺς ἀκούοντας τὸν λόγον.',
   'Eti lalountos tou Petrou ta rhēmata tauta epepesen to pneuma to hagion epi pantas tous akouontas ton logon.',
   '"Eti lalountos" ("while he was yet speaking") — the Spirit does not wait for the sermon''s conclusion or a formal altar call. The word of faith, once heard, is answered by the Spirit before any human response has time to organize itself.',
   'The Holy Spirit sovereignly applies the gospel to whom and when he wills. No human mediation — not even apostolic order — controls the Spirit''s timing; at Caesarea he interrupts the preacher to ratify the message.'),
  (45, 'And they of the circumcision which believed were astonished, as many as came with Peter, because that on the Gentiles also was poured out the gift of the Holy Ghost.',
   'καὶ ἐξέστησαν οἱ ἐκ περιτομῆς πιστοὶ ὅσοι συνῆλθαν τῷ Πέτρῳ, ὅτι καὶ ἐπὶ τὰ ἔθνη ἡ δωρεὰ τοῦ ἁγίου πνεύματος ἐκκέχυται·',
   'Kai exestēsan hoi ek peritomēs pistoi hosoi synēlthan tō Petrō, hoti kai epi ta ethnē hē dōrea tou hagiou pneumatos ekkechytai;',
   '"Ek peritomēs" ("of the circumcision") is Luke''s technical term for Jewish Christians who still held to circumcision-distinction. "Ekkechytai" ("has been poured out") is the same verb used of Pentecost (2:17, 33); this is the Gentile Pentecost, theologically equivalent.',
   'God gave the gift of the Spirit to Gentiles on the same terms as to Jews. The sovereign pouring-out of the Spirit on uncircumcised hearers is God''s own decisive settlement of the question that would occupy Acts 15 — already answered from heaven.'),
  (46, 'For they heard them speak with tongues, and magnify God. Then answered Peter,',
   'ἤκουον γὰρ αὐτῶν λαλούντων γλώσσαις καὶ μεγαλυνόντων τὸν θεόν. τότε ἀπεκρίθη Πέτρος·',
   'Ēkouon gar autōn lalountōn glōssais kai megalynontōn ton theon. Tote apekrithē Petros;',
   '"Glōssais" ("with tongues") — the identical Pentecostal sign of Acts 2. Its purpose here is evidential rather than missional: it authenticates the Gentile reception of the Spirit for the Jewish witnesses who needed to see it.',
   'The tongues at Caesarea are God''s own public seal of Gentile inclusion. Where the Spirit duplicates Pentecost, the church has no choice but to duplicate baptism; divine precedent reshapes ecclesial practice.'),
  (47, 'Can any man forbid water, that these should not be baptized, which have received the Holy Ghost as well as we?',
   'μήτι τὸ ὕδωρ δύναται κωλῦσαί τις τοῦ μὴ βαπτισθῆναι τούτους, οἵτινες τὸ πνεῦμα τὸ ἅγιον ἔλαβον ὡς καὶ ἡμεῖς;',
   'Mēti to hydōr dynatai kōlysai tis tou mē baptisthēnai toutous, hoitines to pneuma to hagion elabon hōs kai hēmeis?',
   'The rhetorical question is the argument: if God has granted the Spirit, no man dare withhold the water. The Caesarean Gentiles receive the Spirit before baptism — reversing the sequence of Samaria (8:15-17) — to demonstrate that God, not the rite, grants the gift.',
   'Baptism follows the Spirit''s sovereign granting; the rite acknowledges what God has already done. No human gatekeeper may withhold the visible sign when the invisible substance has been bestowed.'),
  (48, 'And he commanded them to be baptized in the name of the Lord. Then prayed they him to tarry certain days.',
   'προσέταξεν δὲ αὐτοὺς ἐν τῷ ὀνόματι Ἰησοῦ Χριστοῦ βαπτισθῆναι. τότε ἠρώτησαν αὐτὸν ἐπιμεῖναι ἡμέρας τινάς.',
   'Prosetaxen de autous en tō onomati Iēsou Christou baptisthēnai. Tote ērōtēsan auton epimeinai hēmeras tinas.',
   'Peter "commanded" — the language of apostolic authority, now deployed on behalf of Gentile inclusion. Baptism "in the name of Jesus Christ" is the characteristic Acts formula, functionally equivalent to the trinitarian form (Matt 28:19). The request to "tarry" indicates ongoing instruction and fellowship.',
   'Water baptism publicly seals what the Spirit has wrought invisibly. The Caesarean household enters the visible church under the same ordinance received by Jewish believers — one body, one baptism, one Lord.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 10
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- 3. Word studies
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἑκατοντάρχης', 'hekatontarchēs', 'G1543', 'Centurion, commander of a century (~80-100 men). Key officer rank of the Roman army; six centurions appear favorably in the NT.', 1),
  (2, 'εὐσεβὴς', 'eusebēs', 'G2152', 'Devout, pious. The civic virtue of reverence toward deity; characterizes Cornelius''s pre-conversion piety.', 2),
  (2, 'φοβούμενος τὸν θεὸν', 'phoboumenos ton theon', 'G5399/G2316', 'God-fearer. Technical designation for Gentiles who worshipped Israel''s God without full proselyte conversion.', 3),
  (4, 'μνημόσυνον', 'mnēmosynon', 'G3422', 'Memorial, remembrance-offering. LXX cultic term for grain offering; Cornelius''s prayers ascend as incense-memorial.', 4),
  (10, 'ἔκστασις', 'ekstasis', 'G1611', 'Trance, ecstasy, standing-outside-oneself. State of prophetic rapture in which ordinary consciousness yields to divine revelation.', 5),
  (11, 'ὀθόνην', 'othonēn', 'G3607', 'Sheet, linen cloth. Large sail-like fabric used here as image of creation-container.', 6),
  (12, 'τετράποδα', 'tetrapoda', 'G5074', 'Four-footed creatures. Genesis 1 and Leviticus 11 category of land animals, both clean and unclean.', 7),
  (13, 'θῦσον', 'thyson', 'G2380', 'Kill, slaughter, sacrifice. Sacral verb; more than ''butcher,'' it carries liturgical overtones.', 8),
  (14, 'κοινὸν', 'koinon', 'G2839', 'Common, ritually defiling. Later Jewish term for what pollutes ceremonially; contrasted with ''holy.''', 9),
  (14, 'ἀκάθαρτον', 'akatharton', 'G169', 'Unclean (ritually). Levitical term for forbidden foods and persons; now redefined in Christ.', 10),
  (15, 'ἐκαθάρισεν', 'ekatharisen', 'G2511', 'He cleansed. Divine act of purification; redraws what may and may not be called common.', 11),
  (19, 'διενθυμουμένου', 'dienthymoumenou', 'G1760', 'Pondering, deeply reflecting. Intensified cognition as the Spirit interrupts with direct speech.', 12),
  (20, 'διακρινόμενος', 'diakrinomenos', 'G1252', 'Doubting, discriminating, hesitating. Dual-sense: do not hesitate, and do not make ethnic distinctions.', 13),
  (22, 'ἐχρηματίσθη', 'echrēmatisthē', 'G5537', 'Was divinely warned/instructed. Technical verb for formal revelation from God.', 14),
  (25, 'προσεκύνησεν', 'prosekynēsen', 'G4352', 'Worshipped, prostrated. Highest Roman civic honor, here appropriately refused.', 15),
  (28, 'ἀθέμιτόν', 'athemiton', 'G111', 'Unlawful, forbidden. Refers to social barriers erected by rabbinic halakha, not Torah proper.', 16),
  (28, 'ἀλλοφύλῳ', 'allophylō', 'G246', 'Foreigner, one of another tribe. LXX term for Philistine; here denotes ethnic outsider.', 17),
  (34, 'προσωπολήμπτης', 'prosōpolēmptēs', 'G4381', 'Respecter of persons, partial judge. Hebraism ''face-receiver''; the negation names God as impartial.', 18),
  (35, 'δεκτὸς', 'dektos', 'G1184', 'Acceptable, welcome, received. Indicates God''s openness to the seeker, not the seeker''s justification.', 19),
  (36, 'πάντων κύριος', 'pantōn kyrios', 'G3956/G2962', 'Lord of all. Emphatic ascription of universal sovereignty to Jesus Christ.', 20),
  (38, 'ἔχρισεν', 'echrisen', 'G5548', 'He anointed. Cognate with Christos; Jesus is the anointed one par excellence.', 21),
  (38, 'εὐεργετῶν', 'euergetōn', 'G2109', 'Doing good, bestowing benefit. The compressed summary of Jesus'' ministry.', 22),
  (38, 'καταδυναστευομένους', 'katadynasteuomenous', 'G2616', 'Oppressed, tyrannized. Describes the demonic tyranny Christ came to break.', 23),
  (42, 'ὡρισμένος', 'hōrismenos', 'G3724', 'Appointed, determined. Perfect passive; Christ''s role as judge is an abiding, decreed reality.', 24),
  (42, 'κριτὴς', 'kritēs', 'G2923', 'Judge. Comprehensive eschatological function; Christ judges both living and dead.', 25),
  (43, 'ἄφεσιν', 'aphesin', 'G859', 'Remission, release, forgiveness. Core soteriological term; release from debt of sin through Christ''s name.', 26),
  (44, 'ἐπέπεσεν', 'epepesen', 'G1968', 'Fell upon. Sovereign descent of the Spirit, as at Pentecost (2:3).', 27),
  (45, 'δωρεὰ', 'dōrea', 'G1431', 'Gift, free gift. The unearned character of the Spirit''s coming is stressed.', 28),
  (45, 'ἐκκέχυται', 'ekkechytai', 'G1632', 'Has been poured out. Perfect tense of Joel 2:28-29 fulfillment; the Spirit''s abiding effusion.', 29),
  (46, 'μεγαλυνόντων', 'megalynontōn', 'G3170', 'Magnifying, extolling. Spirit-inspired worship; mirror of Mary''s Magnificat.', 30)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 10 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

